import React from 'react';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import L from 'leaflet';
import { Trash2, Store, Plus } from 'lucide-react';

// Corregir iconos de Leaflet (por defecto no cargan bien en React)
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';

let DefaultIcon = L.icon({
    iconUrl: markerIcon,
    shadowUrl: markerShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41]
});
L.Marker.prototype.options.icon = DefaultIcon;

const Dashboard = () => {
  const locales = [
    { id: 1, nombre: "Mr. Drink", direccion: "Av. Manuel Belgrano 2800, Tucumán", coords: [-26.816, -65.230] },
    { id: 2, nombre: "Mr. Drink 2", direccion: "Av. Sarmiento 356", coords: [-26.820, -65.200] }
  ];

  return (
    <div style={{ display: 'flex', height: 'calc(100vh - 75px)', overflow: 'hidden' }}>
      
      {/* LATERAL IZQUIERDO: LISTA DE LOCALES */}
      <div style={sidebarStyle}>
        <h2 style={{ fontSize: '1.5rem', marginBottom: '5px' }}>Mis Locales</h2>
        <p style={{ color: '#64748b', marginBottom: '30px' }}>Gestiona tus puntos de venta</p>

        <div style={listaContenedor}>
          {locales.map(local => (
            <div key={local.id} style={cardLocal}>
              <div style={iconBox}><Store size={20} color="#e67e22" /></div>
              <div style={{ flex: 1 }}>
                <h4 style={{ margin: 0, fontWeight: 'bold' }}>{local.nombre}</h4>
                <p style={{ margin: 0, fontSize: '0.85rem', color: '#64748b' }}>{local.direccion}</p>
              </div>
              <button style={btnBorrar}><Trash2 size={18} /></button>
            </div>
          ))}
        </div>

        <button style={btnNuevaSucursal}>
          <Plus size={20} /> Nueva Sucursal
        </button>
      </div>

      {/* DERECHA: EL MAPA INTERACTIVO */}
      <div style={{ flex: 1, position: 'relative' }}>
        <MapContainer 
          center={[-26.8167, -65.2167]} // Coordenadas de San Miguel de Tucumán
          zoom={14} 
          style={{ height: '100%', width: '100%' }}
        >
          <TileLayer
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            attribution='&copy; OpenStreetMap contributors'
          />
          {locales.map(local => (
            <Marker key={local.id} position={local.coords}>
              <Popup>{local.nombre}</Popup>
            </Marker>
          ))}
        </MapContainer>
      </div>
    </div>
  );
};

/* --- ESTILOS (Inspirados en tu captura) --- */
const sidebarStyle = {
  width: '400px',
  padding: '40px 25px',
  background: '#ffffff',
  display: 'flex',
  flexDirection: 'column',
  borderRight: '1px solid #e2e8f0'
};

const listaContenedor = { flex: 1, overflowY: 'auto' };

const cardLocal = {
  display: 'flex',
  alignItems: 'center',
  padding: '20px',
  background: '#fff9f5', // Un tono muy suave de naranja
  borderRadius: '16px',
  marginBottom: '15px',
  border: '1px solid #ffeada',
  gap: '15px'
};

const iconBox = {
  background: '#ffffff',
  padding: '10px',
  borderRadius: '12px',
  boxShadow: '0 2px 5px rgba(0,0,0,0.05)'
};

const btnBorrar = {
  background: 'transparent',
  border: 'none',
  color: '#f87171',
  cursor: 'pointer'
};

const btnNuevaSucursal = {
  background: '#e67e22',
  color: 'white',
  padding: '15px',
  borderRadius: '12px',
  border: 'none',
  fontWeight: 'bold',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  gap: '10px',
  cursor: 'pointer',
  marginTop: '20px'
};

export default Dashboard;
